B.F2=new A.es("2026-06-30","\ud83c\udfb5 \ubc30\uacbd\uc74c\uc545\uc774 \uae54\ub838\uc5b4\uc694","\u2022 \uba54\ub274\uc5d4 \ub290\uae0b\ud55c \uc11c\ubd80 \ubd84\uc704\uae30, \ub300\uacb0\uc5d4 \uc0ac\ub9c9\uc758 \uae34\uc7a5\uac10 \u2014 \uc7a5\uba74\uc5d0 \ub9de\ub294 \ubc30\uacbd\uc74c\uc545\uc774 \ud758\ub7ec\uc694\n\u2022 \ucd1d\uc131\xb7\ud321\ud30c\ub808 \uac19\uc740 \ud6a8\uacfc\uc74c\ub3c4 \ub354 \ubb35\uc9c1\ud558\uace0 \uc0dd\uc0dd\ud558\uac8c \ub2e4\ub4ec\uc5c8\uc5b4\uc694\n\u2022 \uc74c\uc545\xb7\ud6a8\uacfc\uc74c\uc740 \uc6b0\uce21 \uc0c1\ub2e8 \uc2a4\ud53c\ucee4 \ubc84\ud2bc\uc73c\ub85c \uc5b8\uc81c\ub4e0 \ub044\uace0 \ucf24 \uc218 \uc788\uc5b4\uc694")
B.F_=new A.es("2026-06-17","\u2728 \ub354 \ubcf4\uae30 \uc88b\uace0, \uc2dc\uc791\ud558\uae30 \uc26c\uc6cc\uc84c\uc5b4\uc694","\u2022 \uae00\uc528\uac00 \ub610\ub837\ud55c \uc0c8 \uae00\uaf34\ub85c \ubc14\ub00c\uc5b4 \uc77d\uae30 \ud55c\uacb0 \ud3b8\ud574\uc84c\uc5b4\uc694\n\u2022 \uc0ac\ub9c9 \ubc30\uacbd(\ub178\uc744\xb7\uc120\uc778\uc7a5)\uc774 \ud55c\uce35 \uba4b\uc2a4\ub7fd\uac8c \uc0c8\ub2e8\uc7a5\ud588\uc5b4\uc694\n\u2022 \ucc98\uc74c \uc624\uc2e0 \ubd84\uaed8\ub294 \uac8c\uc784 \ubc29\ubc95\uc744 \ud31d\uc5c5\uc73c\ub85c \uc0b4\uc9dd \uc548\ub0b4\ud574\ub4dc\ub824\uc694\n\u2022 \uce90\ub9ad\ud130 \uc2b9\ub960 \uc0ac\uc774\ud2b8(cowboy.gg)\ub3c4 \ub2e4\uc2dc \uae54\ub054\ud558\uac8c \ubcf4\uc5ec\uc694")
B.F4=new A.es("2026-06-17","\ud83e\ude84 \ubd80\ub450 \uc800\uc8fc\uac00 \ub354 \uacf5\uc815\ud574\uc84c\uc5b4\uc694",'\u2022 \uc774\ubbf8 \uc800\uc8fc\uc5d0 \uac78\ub9b0 \uc0c1\ub300\uc5d0\uac8c \ub2e4\uc2dc \uc800\uc8fc\ub97c \uac78\uc5b4\ub3c4 \uc2dc\uac04\uc774 \ucd08\uae30\ud654\ub418\uc9c0 \uc54a\uc544\uc694\n\u2022 \uc815\ud574\uc9c4 \ub54c\uac00 \ub418\uba74 \uc800\uc8fc\uac00 \uc5b4\uae40\uc5c6\uc774 \ubc1c\ub3d9\ud574\uc694\n\u2022 \uc758\uc0ac \uc790\ud790\uc774\ub098 \ub9ac\uc14b "\ubb34\ud6a8"\ub85c \uc0b4\uc544\ub0a8\uc558\ub294\ub370 "\uc0ac\ub9dd"\xb7"\uaf5d!" \uc5f0\ucd9c\uc774 \uc798\ubabb \ub728\ub358 \ubb38\uc81c\ub3c4 \uace0\ucce4\uc5b4\uc694')
B.F8=new A.es("2026-06-17","\ud83d\udd75\ufe0f ???\uc758 \uc815\uccb4, \uc774\uc81c \ubc18\ub4dc\uc2dc \ub4dc\ub7ec\ub098\uc694","\u2022 \uc77c\ubd80 \uc9c1\uc5c5\uc73c\ub85c \ubcc0\uc2e0\ud55c ???\uac00 \ub05d\uae4c\uc9c0 \uc815\uccb4\ub97c \uc548 \ubc1d\ud788\ub358 \uacbd\uc6b0\ub97c \uace0\ucce4\uc5b4\uc694\n\u2022 \ud3c9\ud654\uc8fc\uc758\uc790\xb7\uacb0\ud22c\uac00\ucc98\ub7fc \ub9c9\ud310\uc5d0 \ub2a5\ub825\uc774 \ud130\uc9c0\ub294 \uc9c1\uc5c5\uc740 \ubc14\ub85c \uadf8 \uc21c\uac04 \uc815\uccb4\uac00 \uacf5\uac1c\ub3fc\uc694 \u2014 \ub354 \uae54\ub054\ud55c \ub208\uce58 \uc2f8\uc6c0!")
