B.EV=new A.es("2026-06-16","\ud83c\udfb0 \ub8f0\ub81b \ub9ac\ubcfc\ubc84 \uc5f0\ucd9c + \uc88c\uc11d \uc815\ub9ac","\u2022 \ub7ec\uc2dc\uc548\ub8f0\ub81b\uc744 \uc4f0\uba74 \ub9ac\ubcfc\ubc84 \uc2e4\ub9b0\ub354\uac00 \ube59\uae00 \ub3cc\ub2e4 \uc6b4\uba85\uc758 \uc57d\uc2e4\uc774 \ub538\uae4d! \ud558\uace0 \ud130\uc838\uc694\n\u2022 \ucd1d\uad6c\uc5d0\uc11c \ubd88\uaf43 \uc785\uc790\uac00 \ud655 \ud280\uace0, \uba85\uc911\ud558\uba74 \ucda9\uaca9\ud30c\uc640 \ud30c\ud3b8\uc774 \ub354 \ubb35\uc9c1\ud558\uac8c \ud37c\uc838\uc694\n\u2022 \ubd80\ub450 \uc800\uc8fc\ub97c \uac78\uba74 \uc2dc\uc804\uc790\uc5d0\uc11c \ub300\uc0c1\uae4c\uc9c0 \ubcf4\ub77c \uae30\uc6b4\uc774 \ubed7\uc5b4\uac00\ub294 \uac8c \ubcf4\uc5ec\uc694\n\u2022 \uc88c\uc11d\uc758 \uc800\uc8fc \ud45c\uc2dc\uac00 \uc804\uc6a9 \uc904\ub85c \ube60\uc838\uc11c \uc870\uc900 \ub9c8\ucee4\xb7\ub2a5\ub825 \ud69f\uc218\uc640 \uc548 \uacb9\uccd0\uc694")
B.F7=new A.es("2026-06-16","\ud83d\udca5 \ucd1d\uaca9\xb7\ub2a5\ub825 \uc5f0\ucd9c\uc774 \ub354 \ud654\ub048\ud574\uc84c\uc5b4\uc694","\u2022 \ube75\uc57c\ub97c \uc3d8\uba74 \ucd1d\uad6c \uc12c\uad11\ubd80\ud130 \ud0c4\uc774 \ub0a0\uc544\uac00 \uba85\uc911\xb7\ubc29\uc5b4\xb7\ube57\ub098\uac10\uc774 \ud55c\ub208\uc5d0 \ubcf4\uc5ec\uc694\n\u2022 \ubc29\uc5b4\ub294 \ucda9\uaca9\ud30c \ub9c1, \uc7a5\uc804\uc740 \ud0c4\ud53c\uac00 \uc19f\uad6c\uce58\uace0, \uc288\ud37c\ube75\uc57c\ub294 \ub354 \uac15\ub82c\ud55c \ube54\uc73c\ub85c \uaf42\ud600\uc694\n\u2022 \uc758\uc0ac \uc790\ud790(\ucd08\ub85d \uc2ed\uc790)\xb7\ub9ac\uc14b \ubb34\ud6a8\xb7\ubd80\ub450 \uc800\uc8fc \uc624\ub77c\xb7\uc2a4\ub098\uc774\ud37c \uad00\ud1b5\uae4c\uc9c0 \ub2a5\ub825\ub9c8\ub2e4 \uc804\uc6a9 \uc774\ud399\ud2b8\uac00 \ub5a0\uc694\n\u2022 \uc2a4\ubaa8\ucee4\uac00 \uc5f0\ub9c9\uc744 \ucf1c\uba74 \uc548 \ub9de\uc544\ub3c4 \uc5f0\uae30\uac00 \ubaa8\ub77d\ubaa8\ub77d \u2014 \ubb34\uc2a8 \uc77c\uc774 \uc788\uc5c8\ub294\uc9c0 \ub9e4\ubc88 \ubcf4\uc5ec\uc694")
B.Fa=new A.es("2026-06-16","\ud83c\udfa8 \uce90\ub9ad\ud130 \uc77c\ub7ec\uc2a4\ud2b8 \ub4f1\uc7a5!","\u2022 16\uba85\uc758 \ucd1d\uc7a1\uc774\uac00 \uba4b\uc9c4 \uc77c\ub7ec\uc2a4\ud2b8\ub85c \uc0c8\ub2e8\uc7a5\ud588\uc5b4\uc694 \u2014 \uc0c1\uc810\xb7\uac8c\uc784 \uc88c\uc11d \uc5b4\ub514\uc11c\ub098 \uc5bc\uad74\uc774 \ubcf4\uc5ec\uc694\n\u2022 \uc0c1\uc810\uc5d0\uc11c \uce90\ub9ad\ud130\ub97c \ub204\ub974\uba74 \ud070 \uc77c\ub7ec\uc2a4\ud2b8\ub85c \ub2a5\ub825\xb7\uac00\uaca9\uc744 \uc2dc\uc6d0\ud558\uac8c \ubcf4\uc5ec\uc8fc\ub294 \uc0c1\uc138 \ud654\uba74\uc774 \ub5a0\uc694\n\u2022 \uc2a4\ubaa8\ucee4\uac00 \uc5f0\ub9c9\uc744 \ud53c\ud558\uba74 \uc88c\uc11d \uc704\ub85c \uc5f0\uae30\uac00 \ubaa8\ub77d\ubaa8\ub77d \u2014 \ubb34\uc2a8 \uc77c\uc774 \uc77c\uc5b4\ub0ac\ub294\uc9c0 \ud55c\ub208\uc5d0 \ubcf4\uc5ec\uc694")
